const body = $input.first().json.body || $input.first().json;
const now = new Date();
const ticketId = body.ticket_id || ('CMP-' + Date.now().toString().slice(-6));
const severity = body.pcm_percentage > 85 ? 'High' : body.pcm_percentage > 70 ? 'Medium' : 'Low';
return [{
  json: {
    ticket_id: ticketId,
    student_name: body.student_name || 'Unknown Student',
    student_email: body.student_email || '',
    city: body.city || 'Unknown',
    target_exam: body.target_exam || 'JEE/CET',
    complaint_message: body.message || '',
    complaint_category: body.complaint_category || 'General Complaint',
    pcm_percentage: body.pcm_percentage || 0,
    lead_score: body.lead_score || 0,
    severity: severity,
    stage: body.stage || 'Lead',
    source: body.source || 'Chatbot',
    raised_at: now.toISOString(),
    raised_at_readable: now.toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' }),
    escalation_due: new Date(now.getTime() + 2 * 60 * 60 * 1000).toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' }),
    resolution_due: new Date(now.getTime() + 24 * 60 * 60 * 1000).toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' })
  }
}];

// Replace with Postgres node in production
// Query: SELECT complaint_category, COUNT(*) as count FROM tickets
// WHERE query_type='Complaint' AND raised_at > NOW() - INTERVAL '24 hours'
// GROUP BY complaint_category HAVING COUNT(*) > 5
const now = new Date();
const mockPatterns = [
  { complaint_category: 'Faculty Quality', count: 7, threshold_breached: true },
  { complaint_category: 'Batch Timing', count: 3, threshold_breached: false }
];
const breached = mockPatterns.filter(p => p.threshold_breached);
return [{
  json: {
    check_time: now.toLocaleString('en-IN', { timeZone: 'Asia/Kolkata' }),
    patterns_detected: breached.length > 0,
    breached_patterns: breached,
    all_patterns: mockPatterns,
    db_query: "SELECT complaint_category, COUNT(*) as count FROM tickets WHERE query_type='Complaint' AND raised_at > NOW() - INTERVAL '24 hours' GROUP BY complaint_category HAVING COUNT(*) > 5"
  }
}];
